// Crowe ARC sidebar logo — embeds the same icon-only PNG that is wired up
// as the browser-tab favicon, so there is exactly one image asset across the
// product and zero external file dependencies.

const LOGO_DATA_URI = 'data:image/png;base64,';

export default function CroweArcLogo({ size = 36, className = '' }) {
  return (
    <img
      src={LOGO_DATA_URI}
      width={size}
      height={size}
      alt="Crowe ARC"
      draggable={false}
      className={className}
      style={{ display: 'block', objectFit: 'contain' }}
    />
  );
}
